mapper.sql:
FROM tag t





    t.name = #{name,jdbcType=VARCHAR}




        AND EXISTS (
         SELECT 1 FROM concept_tag ct WHERE ct.tag_key = t.key
        )


        AND NOT EXISTS (
         SELECT 1 FROM concept_tag ct WHERE ct.tag_key = t.key
        )

mapper.select:
SELECT DISTINCT ON (ts_rank_cd(t.fulltext_search, query), t.name)


ORDER BY ts_rank_cd(t.fulltext_search, query) DESC, t.name

  LIMIT #{page.limit} OFFSET #{page.offset}
